const resp = $.steps.fetchEmails.response || {};
const messages = resp.messages || resp.data || [];

const emails = messages.slice(0, $.input.maxEmails || 10).map((msg, i) => {
  const headers = msg.payload && msg.payload.headers ? msg.payload.headers : [];
  const getHeader = (name) => {
    const h = headers.find(h => h.name && h.name.toLowerCase() === name.toLowerCase());
    return h ? h.value : '';
  };
  const subject = getHeader('Subject') || msg.subject || '(no subject)';
  const from = getHeader('From') || msg.from || 'unknown';
  const date = getHeader('Date') || msg.date || '';
  const snippet = msg.snippet || msg.body || '';
  return { index: i + 1, subject, from, date, snippet: snippet.slice(0, 200) };
});

let emailSummary = '';
emails.forEach(e => {
  emailSummary += e.index + '. Subject: ' + e.subject + '\n';
  emailSummary += '   From: ' + e.from + '\n';
  emailSummary += '   Date: ' + e.date + '\n';
  emailSummary += '   Preview: ' + e.snippet + '\n\n';
});

return { emails, emailSummary, count: emails.length };

const data = $.steps.extractEmailData.output;
const prompt = `You are an executive assistant helping to triage an email inbox. Analyze the following ${data.count} emails and categorize each one.

EMAILS:
${data.emailSummary}

For each email, determine:
- Category (action-required, follow-up, informational, newsletter, spam/promotional)
- Priority (high, medium, low)
- A brief 1-sentence summary

Also provide an overall inbox summary.

Return ONLY valid JSON:
{
  "inboxSummary": "<2-3 sentence overview of the inbox state>",
  "actionRequired": <number of action-required emails>,
  "categorized": [
    {
      "index": 1,
      "subject": "<subject line>",
      "from": "<sender>",
      "category": "<category>",
      "priority": "<high|medium|low>",
      "summary": "<brief summary>",
      "suggestedAction": "<what to do with this email>"
    }
  ]
}`;
return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { inboxSummary: raw.slice(0, 500), actionRequired: 0, categorized: [] }; }

const ai = $.steps.parseAI.output;
const categorized = ai.categorized || [];

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: ':email: Inbox Digest', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ai.inboxSummary || 'Email analysis complete.' } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Emails analyzed:* ' + categorized.length },
  { type: 'mrkdwn', text: '*Action required:* ' + (ai.actionRequired || 0) }
] });
blocks.push({ type: 'divider' });

const priorityEmoji = { high: ':red_circle:', medium: ':large_orange_circle:', low: ':white_circle:' };
const catEmoji = { 'action-required': ':rotating_light:', 'follow-up': ':leftwards_arrow_with_hook:', 'informational': ':information_source:', 'newsletter': ':newspaper:', 'spam/promotional': ':wastebasket:' };

categorized.slice(0, 10).forEach((e) => {
  const pEmoji = priorityEmoji[e.priority] || ':white_circle:';
  const cEmoji = catEmoji[e.category] || ':email:';
  let text = pEmoji + ' ' + cEmoji + ' *' + (e.subject || 'No subject') + '*\n';
  text += 'From: ' + (e.from || 'unknown') + '\n';
  text += (e.summary || '') + '\n';
  if (e.suggestedAction) text += ':point_right: _' + e.suggestedAction + '_';
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: text } });
});

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Analyzed by One CLI + Claude AI | Gmail Inbox Analyzer' }] });

const fallback = 'Inbox Digest: ' + categorized.length + ' emails analyzed, ' + (ai.actionRequired || 0) + ' need action';
return { blocks, fallback };
